module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);
parameter WIDTH = 16;
parameter N = 16;
parameter N_LOG2 = 4;

reg [4:0] i;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        i <= 5'd0;
    else if (start && i < 5'd17)
        i <= i + 1;
    else if (!start)
        i <= 5'd0;
end

reg done_r;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        done_r <= 1'b0;
    else if (i == 5'd16)
        done_r <= 1'b1;
    else if (i == 5'd17)
        done_r <= 1'b0;
end
assign done = done_r;

reg [WIDTH-1:0] areg;

reg [WIDTH-1:0] breg;

reg [2*WIDTH-1:0] yout_r;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        areg   <= 0;
        breg   <= 0;
        yout_r <= 0;
    end else if (start) begin
        if (i == 5'd0) begin
            areg <= ain;
            breg <= bin;
        end else if (i > 5'd0 && i < 5'd17) begin
            if (areg[i-1]) begin
                yout_r <= ({{(2*WIDTH-N_LOG2-1){1'b0}}, breg} << (i-1)) | yout_r;
            end
        end
    end
end
assign yout = yout_r;
endmodule
